Here’s an example of initializing a ZK proof in Midnight using Compact language:
rust
// Define a simple ZK circuit for proof generation
circuit MyZKProof {
    // Declare private inputs
    private field secret_value;

    // Declare public inputs
    public field public_value;

    // Constraint: secret_value must equal public_value
    constraint secret_value == public_value;
}

// Initialize the circuit
fn main() {
    let secret = field::from(42);
    let public = field::from(42);

    let proof = MyZKProof::prove(secret, public);
    assert!(proof.verify(public));
}
